package com.enterprise.app.service;

import com.enterprise.app.domain.Transaction;
import com.enterprise.app.domain.TransactionStatus;
import com.enterprise.app.domain.User;
import com.enterprise.app.repository.TransactionRepository;
import com.enterprise.app.repository.UserRepository;
import jakarta.persistence.EntityNotFoundException;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;

@Service
public class TransactionService {

    private final TransactionRepository transactionRepository;
    private final UserRepository userRepository;

    public TransactionService(TransactionRepository transactionRepository, UserRepository userRepository) {
        this.transactionRepository = transactionRepository;
        this.userRepository = userRepository;
    }

    @Transactional
    public Transaction createTransaction(long userId, BigDecimal amount, String currency, String externalRef) {
        if (transactionRepository.findByExternalRef(externalRef).isPresent()) {
            throw new IllegalArgumentException("externalRef already exists");
        }
        User user = userRepository.findById(userId).orElseThrow(() -> new EntityNotFoundException("User not found"));

        Transaction t = new Transaction();
        t.setUser(user);
        t.setAmount(amount);
        t.setCurrency(currency);
        t.setExternalRef(externalRef);
        t.setStatus(TransactionStatus.PENDING);

        return transactionRepository.save(t);
    }

    @Transactional
    public Transaction updateStatus(long transactionId, TransactionStatus status) {
        Transaction t = transactionRepository.findById(transactionId)
                .orElseThrow(() -> new EntityNotFoundException("Transaction not found"));
        t.setStatus(status);
        return transactionRepository.save(t);
    }
}

