package com.enterprise.app.api;

import com.enterprise.app.api.dto.CreateUserRequest;
import com.enterprise.app.domain.User;
import com.enterprise.app.domain.UserStatus;
import com.enterprise.app.service.UserService;
import jakarta.validation.Valid;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/users")
public class UserController {

    private final UserService userService;

    public UserController(UserService userService) {
        this.userService = userService;
    }

    @PostMapping
    public User create(@Valid @RequestBody CreateUserRequest req) {
        return userService.createUser(req.getUsername(), req.getEmail(), req.getDisplayName());
    }

    @GetMapping("/{id}")
    public User get(@PathVariable long id) {
        return userService.getUser(id);
    }

    @PatchMapping("/{id}/status")
    public User updateStatus(@PathVariable long id, @RequestParam UserStatus status) {
        return userService.updateStatus(id, status);
    }
}

